logger = logging.getLogger(__name__)

def detect_format_by_content(content):
    """Detect file format by content when extension is ambiguous."""
    lines = content.splitlines()
    has_tabs = any('\t' in line for line in lines if line.strip())
    has_colons = any(':' in line for line in lines if line.strip())

    if has_tabs and not has_colons:
        return 'tsv'
    elif has_colons and not has_tabs:
        return 'yaml'
    elif has_tabs and has_colons:
        # Prefer TSV if tabs are present (more specific delimiter)
        return 'tsv'
    return None

def _download_url(url):
    """Download file from URL using urllib. Returns file path."""
    temp_fd, temp_path = tempfile.mkstemp(suffix='.yaml')
    try:
        urllib = __import__('urllib.request')
        with urllib.request.urlopen(url) as response:
            content = response.read()
        with os.fdopen(temp_fd, 'wb') as f:
            f.write(content)
        return temp_path
    except Exception as e:
        os.close(temp_fd)
        if os.path.exists(temp_path):
            os.remove(temp_path)
        raise ParseError(f"Failed to download file from URL: {e}")

def parse_exchange_file(path, default_compartment):
    """Parse exchange file (TSV or YAML) and yield compound entries.

    Args:
        path: File path or URL to the exchange file
        default_compartment: Default compartment for YAML files without explicit compartment

    Yields:
        Dictionary with keys 'compound', 'lower', 'upper', and optionally 'compartment'

    Raises:
        ParseError: If format cannot be determined, bounds are invalid, or file I/O fails
    """
    # Handle URL input
    temp_file_path = None
    try:
        if isinstance(path, str) and (path.startswith('http://') or path.startswith('https://')):
            # Download file to temporary location
            temp_file_path = _download_url(path)
            path = temp_file_path

        # Read file content
        try:
            with open(path, 'r') as f:
                content = f.read()
        except FileNotFoundError:
            raise ParseError(f"File not found: {path}")
        except IOError as e:
            raise ParseError(f"File I/O error: {e}")

        # Handle empty files
        if not content.strip():
            return

        # Detect format
        fmt = resolve_format(None, path)
        if fmt is None:
            # Content-based detection for ambiguous extensions
            fmt = detect_format_by_content(content)

        if fmt is None:
            raise ParseError("Cannot determine file format")

        # Create context for YAML parsing
        context = FilePathContext(path)

        # Parse based on format
        if fmt == 'tsv':
            try:
                with open(path, 'r') as f:
                    for entry in parse_exchange_table_file(f):
                        # Validate bounds
                        if entry['lower'] > entry['upper']:
                            raise ParseError(
                                f"Invalid bounds for {entry['compound']}: lower ({entry['lower']}) > upper ({entry['upper']})"
                            )
                        yield entry
            except IOError as e:
                raise ParseError(f"File I/O error during TSV parsing: {e}")
        elif fmt == 'yaml':
            try:
                with open(path, 'r') as f:
                    for entry in parse_exchange_yaml_file(context, f, default_compartment):
                        # Validate bounds
                        if entry['lower'] > entry['upper']:
                            raise ParseError(
                                f"Invalid bounds for {entry['compound']}: lower ({entry['lower']}) > upper ({entry['upper']})"
                            )
                        yield entry
            except IOError as e:
                raise ParseError(f"File I/O error during YAML parsing: {e}")
        else:
            raise ParseError(f"Unknown format: {fmt}")

    finally:
        # Clean up temporary file if created
        if temp_file_path and os.path.exists(temp_file_path):
            try:
                os.remove(temp_file_path)
            except OSError:
                pass

