def get_cell_umi_read_string(read_id, sep='_'):
    parts = read_id.rsplit(sep, 2)
    if len(parts) < 3:
        raise ValueError("read_id must contain at least two separators")
    cell_barcode_bytes = parts[1].encode('utf-8')
    umi_bytes = parts[2].encode('utf-8')
    return (umi_bytes, cell_barcode_bytes)

