import os

def parse_theta_results(fname):
    with open(fname, 'r') as f:
        lines = f.readlines()

    # Skip header line
    if len(lines) < 2:
        return None

    data_line = lines[1].strip()
    parts = data_line.split('\t')

    if len(parts) < 4:
        return None

    nll_str, mu_str, c_str, p_star_str = parts[0], parts[1], parts[2], parts[3]

    # Parse NLL
    try:
        nll = float(nll_str)
    except ValueError:
        nll = None

    # Parse mu: first value is normal fraction, rest are tumor fractions
    mu_parts = mu_str.split(',')
    if len(mu_parts) >= 1:
        try:
            mu_normal = float(mu_parts[0])
        except ValueError:
            mu_normal = None
        if len(mu_parts) > 1:
            mu_tumors = []
            for val in mu_parts[1:]:
                try:
                    mu_tumors.append(float(val))
                except ValueError:
                    mu_tumors.append(None)
        else:
            mu_tumors = []
    else:
        mu_normal = None
        mu_tumors = []

    # Parse C: colon-separated list of copy number states
    c_parts = c_str.split(':')
    c_list = []
    for val in c_parts:
        try:
            c_list.append(int(val))
        except ValueError:
            c_list.append(val)  # Keep as string if not an int (placeholder)

    # Parse p*: comma-separated list of probabilities (floats or alphabetic placeholders)
    p_star_parts = p_star_str.split(',')
    p_star_list = []
    for val in p_star_parts:
        try:
            p_star_list.append(float(val))
        except ValueError:
            p_star_list.append(val)  # Keep as string if not a float (placeholder)

    return {
        'NLL': nll,
        'mu_normal': mu_normal,
        'mu_tumors': mu_tumors,
        'C': c_list,
        'p*': p_star_list
    }
